document.addEventListener('DOMContentLoaded', () => {
  initSite('shop.html');
  initShop();
});
let filteredProducts = [...PRODUCTS];
let activeCat    = 'all';
let activeSort   = 'popular';
let searchQuery  = '';
let minPrice     = 0;
let maxPrice     = 5000;
let currentPage  = 1;
const PER_PAGE   = 12;
let isGridView   = true;
function initShop() {
  const params = new URLSearchParams(window.location.search);
  if (params.get('cat'))  { activeCat = params.get('cat'); }
  if (params.get('q'))    { searchQuery = params.get('q'); const si = document.getElementById('shop-search-input'); if (si) si.value = searchQuery; }
  renderSidebar();
  renderSortBar();
  applyFilters();
  document.getElementById('shop-search-input')?.addEventListener('input', e => {
    searchQuery = e.target.value.trim().toLowerCase();
    currentPage = 1;
    applyFilters();
  });
  document.getElementById('sort-select')?.addEventListener('change', e => {
    activeSort = e.target.value;
    applyFilters();
  });
  document.getElementById('view-grid')?.addEventListener('click', () => setView(true));
  document.getElementById('view-list')?.addEventListener('click', () => setView(false));
  document.getElementById('filter-toggle')?.addEventListener('click', () => {
    document.querySelector('.shop-sidebar')?.classList.toggle('mobile-open');
  });
}
function renderSidebar() {
  const list = document.getElementById('category-filter-list');
  if (!list) return;
  const allItem = `
    <div class="filter-item${activeCat === 'all' ? ' active' : ''}" data-cat="all" onclick="setCat('all')">
      <div class="filter-item-left"><span class="filter-emoji">🕉️</span> All Products</div>
      <span class="filter-count">${PRODUCTS.length}</span>
    </div>`;
  const catItems = CATEGORIES.map(c => {
    const count = PRODUCTS.filter(p => p.category === c.id).length;
    return `
    <div class="filter-item${activeCat === c.id ? ' active' : ''}" data-cat="${c.id}" onclick="setCat('${c.id}')">
      <div class="filter-item-left"><span class="filter-emoji">${c.emoji}</span> ${c.name}</div>
      <span class="filter-count">${count}</span>
    </div>`;
  }).join('');
  list.innerHTML = allItem + catItems;
}
function renderSortBar() {
  const sel = document.getElementById('sort-select');
  if (!sel) return;
  sel.value = activeSort;
}
function setCat(cat) {
  activeCat = cat;
  currentPage = 1;
  renderSidebar();
  applyFilters();
}
function setView(grid) {
  isGridView = grid;
  const shopGrid = document.getElementById('shop-grid');
  if (!shopGrid) return;
  shopGrid.classList.toggle('list-view', !grid);
  document.getElementById('view-grid')?.classList.toggle('active', grid);
  document.getElementById('view-list')?.classList.toggle('active', !grid);
}
function applyFilters() {
  let products = [...PRODUCTS];
  if (activeCat !== 'all') products = products.filter(p => p.category === activeCat);
  if (searchQuery) {
    products = products.filter(p =>
      p.name.toLowerCase().includes(searchQuery) ||
      p.categoryName.toLowerCase().includes(searchQuery) ||
      p.tags.some(t => t.includes(searchQuery)) ||
      p.description.toLowerCase().includes(searchQuery)
    );
  }
  if (typeof badgeFilter !== 'undefined' && badgeFilter !== null) {
    products = products.filter(p => p.badge === badgeFilter);
  }
  products = products.filter(p => p.price >= minPrice && p.price <= maxPrice);
  switch (activeSort) {
    case 'price-asc':  products.sort((a, b) => a.price - b.price); break;
    case 'price-desc': products.sort((a, b) => b.price - a.price); break;
    case 'rating':     products.sort((a, b) => b.rating - a.rating); break;
    case 'new':        products.sort((a, b) => b.id - a.id); break;
    default:           products.sort((a, b) => b.reviews - a.reviews); // popular
  }
  filteredProducts = products;
  renderProducts();
  renderResultCount();
  renderPagination();
}
function renderProducts() {
  const grid = document.getElementById('shop-grid');
  if (!grid) return;
  const start = (currentPage - 1) * PER_PAGE;
  const page  = filteredProducts.slice(start, start + PER_PAGE);
  if (page.length === 0) {
    grid.innerHTML = `
      <div class="empty-state" style="grid-column:1/-1">
        <div class="empty-state-icon">🔍</div>
        <h3>No products found</h3>
        <p>Try a different search term or category</p>
        <button class="btn btn-primary" onclick="resetFilters()">Clear Filters</button>
      </div>`;
    return;
  }
  grid.innerHTML = page.map(p => renderProductCard(p)).join('');
  if (!isGridView) grid.classList.add('list-view');
  initScrollReveal();
}
function renderResultCount() {
  const el = document.getElementById('result-count');
  if (el) el.innerHTML = `Showing <strong>${filteredProducts.length}</strong> of <strong>${PRODUCTS.length}</strong> products`;
}
function renderPagination() {
  const container = document.getElementById('pagination');
  if (!container) return;
  const totalPages = Math.ceil(filteredProducts.length / PER_PAGE);
  if (totalPages <= 1) { container.innerHTML = ''; return; }
  let html = `<button class="page-btn" onclick="goPage(${currentPage-1})" ${currentPage===1?'disabled':''}><i class="fas fa-chevron-left"></i></button>`;
  for (let i = 1; i <= totalPages; i++) {
    if (i === 1 || i === totalPages || Math.abs(i - currentPage) <= 1) {
      html += `<button class="page-btn${i===currentPage?' active':''}" onclick="goPage(${i})">${i}</button>`;
    } else if (Math.abs(i - currentPage) === 2) {
      html += `<span class="page-btn" style="pointer-events:none;border:none">…</span>`;
    }
  }
  html += `<button class="page-btn" onclick="goPage(${currentPage+1})" ${currentPage===totalPages?'disabled':''}><i class="fas fa-chevron-right"></i></button>`;
  container.innerHTML = html;
}
function goPage(n) {
  const totalPages = Math.ceil(filteredProducts.length / PER_PAGE);
  if (n < 1 || n > totalPages) return;
  currentPage = n;
  renderProducts();
  renderPagination();
  window.scrollTo({ top: 0, behavior: 'smooth' });
}
function resetFilters() {
  activeCat   = 'all';
  searchQuery = '';
  activeSort  = 'popular';
  currentPage = 1;
  const si = document.getElementById('shop-search-input');
  if (si) si.value = '';
  const ss = document.getElementById('sort-select');
  if (ss) ss.value = 'popular';
  renderSidebar();
  applyFilters();
}